1	import { describe, it, expect } from "vitest";
2	import { processScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  describe("Quote - base premiums", () => {
6	    it("returns 5 G for an empty item list (processing fee only)", () => {
7	      const result = processScenario({
8	        customer: { yearsWithMHPCO: 0 },
9	        steps: [{ op: "quote" as const, items: [] }],
10	      });
11	      expect(result.results[0]).toEqual({ premium: 5 });
12	    });
13	    it.todo("returns 105 G for a single sword (100 base + 5 fee)");
14	    it.todo("returns 65 G for a single amulet (60 base + 5 fee)");
15	    it.todo("returns 85 G for a single staff (80 base + 5 fee)");
16	    it.todo("returns 45 G for a single potion (40 base + 5 fee)");
17	    it.todo("returns 165 G for a sword and an amulet (100 + 60 + 5 fee)");
18	  });
19	
20	  describe("Quote - component premiums", () => {
21	    it.todo("returns 30 G for a single rune (25 base + 5 fee)");
22	    it.todo("returns 55 G for 2 runes (50 base + 5 fee)");
23	    it.todo("returns 65 G for 3 alike runes (60 block premium + 5 fee)");
24	    it.todo("returns 105 G for 4 runes (no block: 4 * 25 = 100 + 5 fee)");
25	    it.todo("returns 80 G for 2 runes + 1 moonstone (no block: different types, 75 + 5 fee)");
26	    it.todo("returns 125 G for 3 runes + 3 moonstones (two blocks: 60 + 60 + 5 fee)");
27	  });
28	
29	  describe("Quote - cursed surcharge", () => {
30	    it.todo("adds 50% surcharge to a cursed sword (100 + 50 + 5 fee = 155 G)");
31	    it.todo("applies cursed surcharge only to the cursed item in a multi-item policy");
32	  });
33	
34	  describe("Quote - high enchantment surcharge", () => {
35	    it.todo("adds 30% surcharge for enchantment level 5 (100 + 30 + 5 fee = 135 G)");
36	    it.todo("does not add surcharge for enchantment level 4");
37	    it.todo("applies both cursed and high enchantment surcharges to the same item");
38	  });
39	
40	  describe("Quote - loyalty discount", () => {
41	    it.todo("applies 20% loyalty discount for customer with 2 years");
42	    it.todo("does not apply loyalty discount for customer with 1 year");
43	  });
44	
45	  describe("Quote - first insurance surcharge", () => {
46	    it.todo("adds 10% first insurance surcharge on policy base premium");
47	  });
48	
49	  describe("Quote - follow-up contract discount", () => {
50	    it.todo("applies 15% follow-up discount on second quote in scenario");
51	  });
52	
53	  describe("Quote - rounding", () => {
54	    it.todo("rounds premium up in MHPCO's favor (ceiling)");
55	  });
56	
57	  describe("Quote - integration", () => {
58	    it.todo("newcomer with cursed sword: 165 G");
59	    it.todo("long-standing customer second contract with cursed enchanted sword: 160 G");
60	  });
61	
62	  describe("Quote - errors", () => {
63	    it.todo("throws error for unknown item type");
64	  });
65	
66	  describe("Claim - basic payout", () => {
67	    it.todo("applies 100 G deductible per damaged item");
68	    it.todo("fully reimburses standard item damage minus deductible");
69	  });
70	
71	  describe("Claim - dragon material", () => {
72	    it.todo("fully reimburses damage to dragon material items minus deductible");
73	  });
74	
75	  describe("Claim - high enchantment reimbursement", () => {
76	    it.todo("reimburses 50% of damage for enchantment >= 8, then applies deductible");
77	    it.todo("50% rule wins over dragon material when enchantment >= 8");
78	  });
79	
80	  describe("Claim - cap", () => {
81	    it.todo("caps total payout at twice the insurance sum");
82	    it.todo("tracks remaining cap across multiple claims on same policy");
83	  });
84	
85	  describe("Claim - multiple damages in one event", () => {
86	    it.todo("applies deductible per damaged item in same event");
87	    it.todo("handles two damages of same item type when policy covers two");
88	  });
89	
90	  describe("Claim - payout rounding", () => {
91	    it.todo("rounds payout down in MHPCO's favor (floor)");
92	  });
93	
94	  describe("Claim - errors", () => {
95	    it.todo("rejects damage for item type not in policy");
96	    it.todo("rejects more damages of a type than policy covers");
97	    it.todo("rejects negative damage amount");
